def shell_page(title: str, summary: str, category: str, cards=None, primary_label="Open all pages") -> str:
    cards = cards or []
    card_html = ''.join(f'<article class="v14-card"><small>{html.escape(k)}</small><h3>{html.escape(h)}</h3><p>{html.escape(p)}</p></article>' for k,h,p in cards)
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{html.escape(title)} · GoalOS</title><meta name="description" content="{html.escape(summary)} {BOUNDARY}"><link rel="stylesheet" href="assets/goalos-site-institutional-command-center-v14.css"><link rel="stylesheet" href="assets/goalos-command-palette-v14.css"></head><body class="v14-page"><a class="v14-skip" href="#main">Skip to content</a><header class="v14-topbar"><a class="v14-brand" href="index.html"><span>α</span><b>GoalOS</b></a><nav>{nav_html()}</nav><button class="v14-menu" data-v14-command>Search /</button></header><main id="main" class="v14-shell"><section class="v14-hero compact"><div><p class="v14-kicker">{html.escape(category)}</p><h1>{html.escape(title)}</h1><p class="v14-lede">{html.escape(summary)}</p><div class="v14-actions"><a class="v14-primary" href="site-map.html">{primary_label}</a><a class="v14-secondary" href="trust-boundary.html">Trust boundary</a></div></div><aside class="v14-console"><b>Route status</b><code>category: {html.escape(category)}\nstate: DISCOVERABLE\nboundary: preserved\nexternal actions: 0</code></aside></section><section class="v14-grid">{card_html}</section><section class="v14-boundary"><b>Public-alpha boundary.</b> {BOUNDARY}<br>{TOKEN_BOUNDARY}</section></main><script src="assets/goalos-site-index-data-v14.js"></script><script src="assets/goalos-command-palette-v14.js"></script></body></html>'''

