def build_routes():
    routes=[]
    for p in sorted(PUBLIC.glob('*.html')):
        name=p.name; title=extract_title(p)
        if name in EXPECTED:
            title, summary, cat=EXPECTED[name]
        else:
            cat=classify(name,title); summary=description_for(name,title,cat)
        routes.append({"path":name,"title":title,"summary":summary,"category":cat,"role":role_for(cat),"gate":gate_for(cat),"next_state":next_state_for(cat)})
    core_order={href:i for i,(href,_) in enumerate(CORE_NAV)}
    routes.sort(key=lambda r:(999 if r['category']=='System' else core_order.get(r['path'],100), r['category'], r['title']))
    return routes

def route_cards(rs, limit=80):
    return ''.join(f'<article class="v14-route" data-route-card><small>{html.escape(r["category"])}</small><div><b>{html.escape(r["title"])}</b><p>{html.escape(r["summary"])}</p></div><a href="{html.escape(r["path"])}">Open →</a></article>' for r in rs[:limit])

def cards(items):
    return ''.join(f'<article class="v14-card"><small>{html.escape(k)}</small><h3>{html.escape(h)}</h3><p>{html.escape(p)}</p><a href="{href}">Open →</a></article>' for k,h,p,href in items)

