# Link audit
broken=[]; html_files={p.name for p in PUBLIC.glob('*.html')}
for p in PUBLIC.glob('*.html'):
    txt=p.read_text(errors='ignore')
    for href in re.findall(r'href=["\']([^"\']+)["\']',txt):
        if href.startswith(('#','http','mailto:','tel:','javascript:')): continue
        if href.startswith('assets/') or href.startswith('downloads/') or href.endswith(('.xml','.json','.webmanifest','.txt')): continue
        target=href.split('#')[0].split('?')[0]
        if target.endswith('/'): target+='index.html'
        if '/' not in target and target.endswith('.html') and target not in html_files:
            broken.append({"page":p.name,"href":href})
